      out.write("    estados_cita:'🔄 **Appointment statuses (Doctor)**\\n\\n🟡 **Scheduled** → Confirm or Cancel\\n🟢 **Confirmed** → Mark as Attended\\n✅ **Attended** → Final status\\n🔴 **Cancelled** → Final status\\n\\n_From: Appointments → View detail_',\n");
